sys_script_include.script:
function GetInstanceAIStatus()
{
	aistatus = {};

	aistatus.now_assist_agents_installation = {};
	aistatus.now_assist_agents_installation.title = 'Now Assist AI Agents plugin installation';
	aistatus.now_assist_agents_installation.status = IsNowAssistAIAgentsInstalled();
	aistatus.now_assist_agents_installation.info = 'Is true if required plugins are installed to use AI Agents. The "Now Assist AI Agents" plugin can only be installed as a dependency. Installing the "Now Assist for Creator" (sn_now_creator) is one option.';
	aistatus.now_assist_agents_installation.url = GetInstanceUrl() + 'now/app-manager/home/app/id/32808450431302106c3603295bb8f245/';



	aistatus.now_assist_panel = {};
	aistatus.now_assist_panel.title = 'Now Assist Panel activation';
	aistatus.now_assist_panel.status = false;
	aistatus.now_assist_panel.info = 'True if the Now Assist Panel is "turned on" on.';
	aistatus.now_assist_panel.url = GetInstanceUrl() +'now/now-assist-admin/now-assist-panel';
	var grNAS = new GlideRecord('sn_nowassist_settings');
	grNAS.addQuery('type','=','nap');
	grNAS.addQuery('name','=','Now Assist Panel Settings');
	grNAS.addQuery('active','=',true);
	grNAS.query();
	while (grNAS.next())
	{
		var variables = GetVariablesFromRecord(grNAS);
		if (GetValue(variables,'nap_enabled','value') == 1)
		{
			aistatus.now_assist_panel.status = true;
		}
	}



	aistatus.now_assist_panel_platform = {};
	aistatus.now_assist_panel_platform.title = 'Now Assist Panel Deployment Channel configuration';
	aistatus.now_assist_panel_platform.status = false;
	aistatus.now_assist_panel_platform.info = 'Is true if the Now Assist Panel Deployment Channel is configured for "Now Assist Panel - Platform (default)".';
	aistatus.now_assist_panel_platform.url = GetInstanceUrl()+'now/conversational-studio/assistants/all';
	if (IsValidTable('sys_now_assist_deployment_channel') == true)
	{
		var grNAPDC = new GlideRecord('sys_now_assist_deployment_channel');
		grNAPDC.addQuery('active','=','true');
		grNAPDC.addQuery('config_type','=','');
		grNAPDC.addQuery('document_table','=','sys_ux_app');
		grNAPDC.addQuery('experience','=','self_service_dialog'); 
		grNAPDC.query();
		while (grNAPDC.next() == true)
		{
			if (grNAPDC.now_assist_deployment.getDisplayValue() == 'Now Assist Panel - Platform (default)')
			{
				aistatus.now_assist_panel_platform.status = true;
			}	
		}
	}



	aistatus.now_assist_ignore_fulfiller_subscription_check = {};
	aistatus.now_assist_ignore_fulfiller_subscription_check.title = 'Ignore Fulfiller Subscription Check';
	var strPropName = 'sn_nowassist_admin.ignoreFulfillerSubscriptionCheck';
	aistatus.now_assist_ignore_fulfiller_subscription_check.status = 
		GetBoolValue(
			GetProperty(strPropName));
	aistatus.now_assist_ignore_fulfiller_subscription_check.info = 
		'True if the system property "' + strPropName + '" is set to "true". Setting this system property is documented as a fix to PRB1965167.';

	var grProp = GetPropertyRecord(strPropName);
	var strUrl = '';
	if (IsValidRecord(grProp) == true)
	{
		strUrl = GetInstanceRecordUrl('sys_properties',grProp.sys_id);
	}
	else
	{
		strUrl = GetInstanceListUrl('sys_properties','','name='+strPropName,0);
	}
	aistatus.now_assist_ignore_fulfiller_subscription_check.url = strUrl;

	// LLM Gateway connection config
	aistatus.llmgateway_connection = {};
	/*
	var grSSE = new GlideRecord('sys_service_endpoint');
	grSSE.addQuery('url','=','https://llmgateway-dart');
	grSSE.query();
	if (grSSE.getRowCount() > 0)
	{
		aistatus.llmgateway_config.status = false;
	}
	else
	{
		aistatus.llmgateway_config.status = true;
	}
	*/
	/*
	aistatus.llmgateway_config.info = 
		'No sys_service_endpoint record should point to the outdated url: https://llmgateway-dart. The status is true, if no record points to the outdated url. If at least one record points to the outdated url, the status is false. Follow instructions in KB3024782 to fix this.';
*/

/*
	aistatus.llmgateway_config.info = 
		'No sys_service_endpoint record should point to the outdated url: https://llmgateway-dart. The status cannot be determined unless the script is executed as maint. Follow instructions in KB3024782 to fix this.';
	aistatus.llmgateway_config.url = GetInstanceListUrl('sys_service_endpoint');
*/


	var grConnection = new GlideRecord('http_connection');
	grConnection.addQuery('name','=','Now LLM');
	grConnection.query();
	var bStatus = false;
	if (grConnection.getRowCount() == 1)
	{
		if (grConnection.next())
		{
			aistatus.llmgateway_connection.url = GetInstanceRecordUrl('http_connection',grConnection.sys_id);
			var strUrl = GetStringValue(grConnection.connection_url);
			if (strUrl == 'https://llmgateway-dart-default-dart001.aus100.service-now.com')
			{
				bStatus = true;
			}
		}
	}
	aistatus.llmgateway_connection.status = bStatus;

	aistatus.llmgateway_connection.info = 
		'The HTTP Connection record "Now LLM" should point to the outdated url: "https://llmgateway-dart". Follow instructions in KB3084849 to fix this.';





	return aistatus;
}
